+            .unwrap();
+        conn.execute(
+            "CREATE TABLE child (id INTEGER PRIMARY KEY, parent_id INTEGER REFERENCES parent(id))",
+        )
+        .unwrap();
+        // Should succeed even without parent, because FK enforcement is off.
+        conn.execute("INSERT INTO child VALUES (1, 99)").unwrap();
+    }
+
